 takes the following attributes,\nall of which also provide read-only accessor methods:\n\n=head3 home\n\nThe URL of the applications home page.  Defaults to the C<< GADS_HOME >>\nenvironment variable.\n\n\nhas home => (\n    is => 'ro',\n    default => \\&_default_home,\n);\n\nsub _default_home {\n    my $home = $ENV{GADS_HOME} // 'http://localhost:3000';\n    $home =~ s{ (?<= / > $ ) }{}x;\n    return $home;\n}\n\n=head3 username\n\nThe username of an existing account to log in to GADS with.  Defaults to\nthe C<< GADS_USERNAME >> environment variable.\n\n\nhas username => (\n    is => 'ro',\n    default => \\&_default_username,\n);\n\nsub _default_username {\n    return $ENV{GADS_USERNAME} // die \"Missing GADS_USERNAME\";\n}\n\n=head3 password\n\nThe password for the existing GADS account.  Defaults to the C<<\nGADS_PASSWORD >> environment variable.\n\n\nhas password => (\n    is => 'ro',\n    default => \\&_default_password,\n);\n\nsub _default_password {\n    return $ENV{GADS_PASSWORD} // die \"Missing GADS_PASSWORD\";\n}\n\n=head3 webdriver\n\nAn object which supports the interface used by L<< WebDriver::Tiny >>.\nDefaults to using an object of that class that connects to port 4444.\n\n\nhas webdriver => (\n    is => 'ro',\n    default => sub {\n        WebDriver::Tiny->new(\n            port => 4444,\n            capabilities => {\n                'goog:chromeOptions' => { args => ['--headless'] },\n            },\n        );\n    },\n);\n\n=head2 type_into_field\n\nFind an element specified by a CSS selector contained in the first\nargument, and enter a value specified by the second argument into that\nfield.","parameters":[{"label":"$self"},{"label":"$selector"},{"label":"$value"}]}},{"name":"dies","kind":12,"line":106},{"name":"tries","kind":12,"line":106},{"children":[{"name":"$self","containerName":"go_to_url","definition":"my","kind":13,"localvar":"my","line":123},{"line":123,"containerName":"go_to_url","name":"$url","kind":13},{"kind":13,"containerName":"go_to_url","name":"$self","line":125},{"line":125,"kind":12,"containerName":"go_to_url","name":"webdriver"},{"line":125,"containerName":"go_to_url","name":"get","kind":12},{"line":125,"name":"$self","containerName":"go_to_url","kind":13},{"line":125,"kind":12,"name":"home","containerName":"go_to_url"},{"line":125,"kind":13,"name":"$url","containerName":"go_to_url"}],"kind":12,"name":"go_to_url","line":122,"signature":{"parameters":[{"label":"$self"},{"label":"$url"}],"label":"go_to_url($self,$url)","documentation":"package GADSDriver;\n\nuse v5.24.0;\nuse Moo;\n\nuse WebDriver::Tiny ();\n\n=head1 NAME\n\nGADSDriver - GADS-specific wrapper for WebDriver::Tiny\n\n=head1 SYNOPSIS\n\n    use GADSDriver ();\n    my $gads = GADSDriver->new(...);\n    ...;\n    my $webdriver = $gads->webdriver;\n\n=head1 METHODS\n\n=head2 new\n\nA standard L<< Moo >> constructor which takes the following attributes,\nall of which also provide read-only accessor methods:\n\n=head3 home\n\nThe URL of the applications home page.  Defaults to the C<< GADS_HOME >>\nenvironment variable.\n\n\nhas home => (\n    is => 'ro',\n    default => \\&_default_home,\n);\n\nsub _default_home {\n    my $home = $ENV{GADS_HOME} // 'http://localhost:3000';\n    $home =~ s{ (?<= / > $ ) }{}x;\n    return $home;\n}\n\n=head3 username\n\nThe username of an existing account to log in to GADS with.  Defaults to\nthe C<< GADS_USERNAME >> environment variable.\n\n\nhas username => (\n    is => 'ro',\n    default => \\&_default_username,\n);\n\nsub _default_username {\n    return $ENV{GADS_USERNAME} // die \"Missing GADS_USERNAME\";\n}\n\n=head3 password\n\nThe password for the existing GADS account.  Defaults to the C<<\nGADS_PASSWORD >> environment variable.\n\n\nhas password => (\n    is => 'ro',\n    default => \\&_default_password,\n);\n\nsub _default_password {\n    return $ENV{GADS_PASSWORD} // die \"Missing GADS_PASSWORD\";\n}\n\n=head3 webdriver\n\nAn object which supports the interface used by L<< WebDriver::Tiny >>.\nDefaults to using an object of that class that connects to port 4444.\n\n\nhas webdriver => (\n    is => 'ro',\n    default => sub {\n        WebDriver::Tiny->new(\n            port => 4444,\n            capabilities => {\n                'goog:chromeOptions' => { args => ['--headless'] },\n            },\n        );\n    },\n);\n\n=head2 type_into_field\n\nFind an element specified by a CSS selector contained in the first\nargument, and enter a value specified by the second argument into that\nfield.\n\n\nsub type_into_field {\n    my ( $self, $selector, $value ) = @_;\n    my $webdriver = $self->webdriver;\n\n    my $field_el = $webdriver->find( $selector, dies => 0, tries => 20 );\n    if ( 0 == $field_el->size ) {\n        return undef;\n    }\n    else {\n        $field_el->send_keys( $value );\n        return $self;\n    }\n}\n\n=head2 go_to_url\n\nTakes one argument, a URL to load relative to the application's root URL."},"detail":"($self,$url)","range":{"start":{"line":122,"character":0},"end":{"character":9999,"line":126}},"definition":"sub","containerName":"main::"}]}